105	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:152.0) Gecko/20100101 Firefox/152.0	2026-07-14 01:34:45.954072+00	2026-07-14 01:37:57.804631+00	192	{"6947": "0982355868", "6948": [[["Hiệu năng hệ thống", "Cao"], ["Khả năng mở rộng", "Cao"], ["Tính sẵn sàng", "Cao"], ["An toàn thông tin", "Cao"], ["Sao lưu và phục hồi dữ liệu", "Cao"], ["Khả năng tích hợp", "Cao"], ["Khả năng khai thác trên thiết bị di động", "Cao"], ["Khả năng sử dụng", "Cao"], ["Khả năng bảo trì", "Cao"], ["Khả năng nâng cấp", "Cao"], ["Khả năng mở rộng tích hợp", "Cao"], ["Khả năng truy cập đa nền tảng(Web/Mobile/Tablet)", "Cao"], ["Tính thân thiện giao diện", "Cao"]]], "6949": "Không", "6950": "Các yêu cầu trên đã được thống nhất.", "6951": "Quảng Bị", "6952": "ks2_quangbi", "6953": "Không", "6954": "Chuyên viên", "6955": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "6956": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6957": "Không", "6958": [["", "", ""]], "6961": [["", "", "", "", "", "", "", "", ""]], "6962": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6963": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "email": "", "phone": "", "agency": "Quảng Bị", "position": "", "full_name": "ks2_quangbi", "department": "Quảng Bị", "organization": "Quảng Bị"}	f	\N	f	f	2026-07-14 01:34:45.954159+00	502	21	{"sec_mrji32jc_02myx": 100, "sec_mrji3pol_08ygj": 100, "se