541	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 09:56:31.252743+00	2026-07-14 10:08:47.81119+00	737	{"6947": "hamhuong091195@gmail.com", "6948": "Từ Liêm", "6949": "ks2_tuliem", "6950": "Chuyên viên Phòng Văn hoá - Xã hội", "6951": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "6953": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "6954": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "6955": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6956": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6960": "Trong quá trình khảo sát mức độ hài lòng (SIPAS), nhiều người dân chưa phân biệt rõ chức năng, nhiệm vụ giữa Trung tâm Phục vụ hành chính công và UBND phường, nên thường đánh giá chung đối với UBND phường khi không hài lòng về quá trình giải quyết thủ tục hành chính. Điều này ảnh hưởng đến tính khách quan của kết quả khảo sát và chưa phản ánh đúng nỗ lực cải thiện chất lượng phục vụ của UBND phường. Đề nghị nghiên cứu hoàn thiện phương pháp khảo sát, phân định rõ trách nhiệm của từng cơ quan trong quá trình cung cấp dịch vụ hành chính công, bảo đảm kết quả đánh giá khách quan, công bằng.", "6961": [["", "", ""]], "6963": "Không có yêu cầu bổ sung.", "email": "", "phone": "", "agency": "Từ Liêm", "position": "", "full_name": "ks2_tuliem", "department": "Từ Liêm", "organization": "Từ Liêm"}	f	\N	f	f	2026-07-14 09:56:31.252798+00	476	21	{"sec_mrji32jc_02myx": 100, "sec_mrji3pol_08ygj": 100, "sec_mrji3p