hảo sát tham gia đầy đủ, nâng cao chất lượng công tác khảo sát", "email": "", "phone": "", "agency": "Thạch Thất", "position": "", "full_name": "ks2_thachthat", "department": "Thạch Thất", "organization": "Thạch Thất"}	f	\N	f	f	2026-07-14 02:38:12.507296+00	569	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	submitted
