319	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 04:41:38.636489+00	2026-07-14 04:48:33.495654+00	415	{"6947": "0969406565", "6948": "Suối Hai", "6949": "ks2_suoihai", "6950": "Chuyên viên", "6951": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "6953": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6954": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "6955": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6956": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6958": "Quản lý đợt khảo sát và đối tượng khảo sát.\\nThu thập, quản lý phiếu khảo sát và theo dõi tiến độ thực hiện.\\nDashboard và báo cáo phân tích kết quả khảo sát theo thời gian thực.", "6959": "Quản lý đợt khảo sát và bộ câu hỏi (tạo, cấu hình, phát hành khảo sát).\\nQuản lý đối tượng và thu thập phiếu khảo sát (theo dõi tiến độ, kiểm soát tỷ lệ tham gia).\\nDashboard và báo cáo tổng hợp (thống kê kết quả, phân tích, xuất báo cáo phục vụ chỉ đạo điều hành).", "6960": "Làm rõ quy trình nghiệp vụ điều tra, khảo sát và trách nhiệm của từng cấp, từng đơn vị.\\nNghiên cứu khả năng liên thông, chia sẻ dữ liệu với các hệ thống dùng chung và cơ sở dữ liệu hiện có của Thành phố.\\nLàm rõ yêu cầu về bảo mật, phân quyền và bảo vệ dữ liệu cá nhân, bảo đảm tuân thủ quy định của pháp luật và an toàn thông tin.", "6961": [["1", "2", "3"]], "6963": "Đề nghị bổ sung thêm sau khảo sát.", "email": "", "phone": "", "agency": "Suối Hai", "position": "", "full_name": "ks2_suoihai", "department": "Suối Hai", "organization": "Suối Hai"}	f	\N	f	f	2026-07-14 04:41:38.636651+00	571	21	{"sec_mrji32jc_02myx": 100, "sec_mrji3pol_08ygj": 100, "sec_mrji3pol_kjxj5": 100, "sec_mrji3pom_xwahu": 100, "sec_mrji4ctm_06kdb": 0, "sec_mrji4ctm_gtanp": 100, "sec_mrji4ctm_w2j5m": 100, "sec_mrji4zz8_b0vue": 100, "sec_mrji4zz8_eyyqa": 0, "sec_mrji4zz8_qvwvf": 100}	draft
