l, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6815": {"data": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, null, null], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6816": {"data": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6817": {"data": [[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6818": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6819": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, null, null], [null, null, null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "6820": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "6821": "Đáp ứng", "6822": "Trong công tác Cải cách hành chính (CCHC) và chuyển đổi số tại cấp cơ sở (như UBND cấp phường), việc quản lý và vận hành hệ thống Công nghệ thông tin (CNTT) là \\"bệ đỡ\\" cho toàn bộ các hoạt động nghiệp vụ. Tuy nhiên, thực tế vận hành tại địa phương hiện nay đang vấp phải 4 nhóm khó khăn, vướng mắc cốt lõi sau đây:\\n\\n1. Hạ tầng kỹ thuật chưa đồng bộ và thiếu tính dự phòng\\nHạ tầng phần cứng tại cấp phường thường được đầu tư phân tán, thiếu tính đồng bộ và chưa đáp ứng được yêu cầu của các hệ thống phần mềm thế hệ mới:\\n\\nTrang thiết bị xuống cấp: Máy tính tại bộ phận Một cửa và các phòng chuyên môn đa số cấu hình cũ, tốc độ xử lý chậm, thường xuyên xảy ra tình trạng giật lag khi phải gánh các tác vụ nặng (như chạy cùng lúc phần mềm Một cửa, phần mềm hộ tịch, scan tài liệu và ký số).\\n\\nĐường truyền và mạng nội bộ yếu: Đường truyền Internet/WAN tại một số thời điểm không ổn định, băng thông hẹp dẫn đến việc đồng bộ dữ liệu lên hệ thống của Quận/Thành phố bị nghẽn.\\n\\nThiếu thiết bị dự phòng: Khi xảy ra sự cố phần cứng (hỏng ổ cứng, hỏng máy scan, lỗi cổng ký số), quy trình xử lý của cán bộ lập tức bị tê liệt do không có thiết bị thay thế ngay lập tức.\\n\\n2. Sự phức tạp và thiếu liên thông của các hệ thống phần mềm (Silo dữ liệu)\\nCán bộ cấp cơ sở hiện đang là đối tượng chịu áp lực lớn nhất từ việc \\"loạn\\" phần mềm quản lý:\\n\\nTình trạng \\"một cửa, nhiều cổng\\": Để giải quyết một hồ sơ liên thông, công chức phải đăng nhập, thao tác và nhập liệu trùng lặp trên nhiều hệ thống khác nhau (Ví dụ: vừa nhập trên Hệ thống thông tin giải quyết TTHC của Thành phố, vừa phải nhập vào cơ sở dữ liệu chuyên ngành của Bộ ngành chủ quản). các hệ thống này chưa \\"nói chuyện\\" được với nhau qua API.\\n\\nLỗi hệ thống thường xuyên: Các phần mềm dùng chung cấp tỉnh/thành phố hoặc quốc gia thường xuyên có các đợt nâng cấp, bảo trì đột xuất hoặc bị nghẽn mạng trong giờ cao điểm, khiến cán bộ không thể tiếp nhận hay trả kết quả đúng hạn cho người dân, gián tiếp kéo tụt điểm SLA của phường.\\n\\n3. Nguồn nhân lực CNTT tại chỗ vừa thiếu vừa yếu\\nĐây là vướng mắc lớn nhất ảnh hưởng đến tính bền vững của việc vận hành hệ thống:\\n\\nKhông có cán bộ chuyên trách CNTT: Theo quy định biên chế cấp phường, không có vị trí chuyên trách dành riêng cho kỹ sư CNTT. Công việc này thường được giao kiêm nhiệm cho công chức Văn phòng - Thống kê hoặc Văn hóa - Xã hội (những người không có chuyên môn sâu về mạng, an toàn thông tin hay quản trị hệ thống).\\n\\nKhả năng ứng phó sự cố chậm: Khi xảy ra lỗi phần mềm, lỗi chữ ký số hoặc sự cố mạng, cán bộ kiêm nhiệm không tự xử lý được mà phải chờ đợi sự hỗ trợ từ đội ngũ kỹ thuật cấp Quận hoặc nhà thầu xây dựng phần mềm, gây gián đoạn công việc kéo dài.\\n\\nTrình độ nhận thức về an toàn thông tin (ATTT) hạn chế: Cán bộ công chức dễ gặp các nguy cơ về bảo mật (lộ mật khẩu, click vào link chứa mã độc, sử dụng USB chưa quét virus), đe dọa an toàn dữ liệu của toàn cơ quan.\\n\\n4. Khó khăn trong quản lý tài chính và cơ chế bảo trì, vận hành\\nThiếu kinh phí duy trì hằng năm: Nguồn ngân sách chi thường xuyên của cấp phường rất hạn hẹp, khó phân bổ kinh phí cho các hoạt động nâng cấp phần cứng, bảo trì mạng định kỳ hay mua sắm bản quyền phần mềm diệt virus chuyên dụng.\\n\\nVướng mắc trong quy trình mua sắm, sửa chữa: Quy trình thủ tục để phê duyệt kinh phí sửa chữa thiết bị CNTT hư hỏng thường rườm rà, phải qua nhiều bước phê duyệt, không đáp ứng được yêu cầu \\"sửa chữa ngay\\" để phục vụ người dân tại bộ phận Một cửa.", "6823": "Nâng cấp hệ thống cho phù hợp chung với Thành phố Hà Nội", "6824": {"data": [[null, "Có", null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, "Có", null, "Chương Mỹ"], [null, null, null, "Chương Mỹ"], [null, "Có", null, "Chươ