199	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 03:05:26.541063+00	2026-07-14 03:26:45.886232+00	1280	{"6947": "ubnd_hongvan@hanoi.gov.vn/0989278883", "6948": "UBND Hồng Vân", "6949": "Đỗ Trọng Đoàn", "6950": "Chuyên viên", "6951": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "6953": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Làm sạch dữ liệu", "Tổng hợp kết quả", "Phân tích dữ liệu", "Quản lý báo cáo", "Dashboard điều hành", "Quản lý hồ sơ khảo sát", "Quản lý tài liệu khảo sát", "Quản lý danh mục dùng chung", "Theo dõi tiến độ khảo sát", "Quản lý nhật ký", "Quản lý cấu hình", "Quản lý tham số hệ thống", "Quản lý thông báo và nhắc việc", "Quản lý thông báo hệ thống", "Quản lý danh mục địa bàn, đơn vị hành chính"]], "6954": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "6955": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6956": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6958": "Theo dõi, quản lý tiến độ thực hiện nhiệm vụ CCHC.\\nTheo dõi các chỉ tiêu, tiêu chí Chỉ số CCHC.\\nQuản lý hồ sơ, tài liệu kiểm chứng.\\nTổng hợp số liệu và báo cáo tự động.", "6959": "Quản lý kế hoạch và nhiệm vụ CCHC.\\nDashboard theo dõi, đánh giá Chỉ số CCHC.\\nQuản lý hồ sơ, tài liệu kiểm chứng.\\nHệ thống báo cáo và thống kê.\\nCảnh báo nhiệm vụ quá hạn và nhắc việc.", "6960": "Phương án tích hợp, đồng bộ dữ liệu với các hệ thống dùng chung.\\nCơ chế phân quyền, chia sẻ và khai thác dữ liệu giữa các đơn vị.\\nQuy trình cập nhật, xác thực và chuẩn hóa dữ liệu CCHC.", "6961": [["Cần", "Cần", "Rất cần"]], "696