399	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 08:07:22.610999+00	2026-07-14 08:21:49.204929+00	204	{"6947": "giahan.129@gmail.com", "6948": "Đan Phượng", "6949": "ks2_danphuong", "6950": "Lãnh đạo UBND xã Đan Phượng", "6951": [["", "", "", "", "", "", "", "", "", "", "", "", ""]], "6953": [["Cao", "Cao", "Cao", "Cần", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6954": [["Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần", "Cần"]], "6955": {"data": [[null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6956": [["Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao", "Cao"]], "6958": "Hệ thống cần quản lý tập trung đối tượng khảo sát; hỗ trợ khảo sát trực tuyến qua nhiều kênh; theo dõi tiến độ theo thời gian thực; tự động tổng hợp, phân tích kết quả và xuất báo cáo, Dashboard phục vụ công tác chỉ đạo, điều hành.", "6959": "Ưu tiên triển khai các chức năng: (1) Quản lý đối tượng khảo sát; (2) Tổ chức, theo dõi và đôn đốc quá trình khảo sát theo thời gian thực; (3) Tự động tổng hợp, phân tích kết quả và xuất báo cáo, Dashboard phục vụ công tác chỉ đạo, điều hành.", "6960": "Cần nghiên cứu cơ chế liên thông dữ liệu, xác thực đối tượng khảo sát, bảo mật thông tin, chuẩn hóa biểu mẫu báo cáo và khả năng mở rộng, tích hợp hệ thống trong tương lai.", "6961": [["1", "2", "3"]], "6963": "Đề nghị bổ sung thêm sau khảo sát.", "email": "", "phone": "", "agency": "Đan Phượng", "position": "", "full_name": "ks2_danphuong", "department": "Đan Phượng", "organization": "Đan Phượng"}	f	\N	f	f	2026-07-