ull, null, null, "Ứng Thiên"], [null, null, null, "Ứng Thiên"], [null, null, null, "Ứng Thiên"], [null, null, null, "Ứng Thiên"]], "type": "grid"}, "email": "", "phone": "", "agency": "Ứng Thiên", "position": "", "full_name": "ks2_ungthien", "department": "Ứng Thiên", "organization": "Ứng Thiên"}	f	\N	f	f	2026-07-14 03:45:49.677114+00	501	18	{"sec_mrd51u8k_s7xvx": 0, "sec_mrd52i20_bxs8q": 0, "sec_mrd589py_n4ccb": 0, "sec_mrd58wv7_h9r0m": 0, "sec_mrd5h8uk_83ljt": 0, "sec_mrd5h8uk_lb1ld": 0, "sec_mrd5h8uk_q8t9f": 0, "sec_mrd5h8uk_zlvj1": 0, "sec_mrd5h8uk_znbx8": 0, "sec_mrd5hvzu_sb784": 0, "sec_mrd5hvzv_7jcz3": 0, "sec_mrd5hvzv_a4wue": 0, "sec_mrd5hvzv_ae5ra": 0, "sec_mrd5hvzv_vsvm8": 0, "sec_mrd5hvzv_ztdcy": 0, "sec_mrd5ij53_k401z": 100, "sec_mrd5ij53_lxnd3": 0}	draft
