dân hoặc doanh nghiệp thiếu mặn mà với việc điền phiếu khảo sát, dẫn đến việc lấy phiếu còn khó khăn.", "6835": "Đề nghị tiếp tục hoàn thiện phiếu khảo sát ngắn gọn, dễ hiểu để người tham gia trả lời phiếu hoàn thiện nhanh chóng. Phiếu nên thiết kế dễ hiểu, \\"không nên thiết kế theo kiểu lúc đáp án 5 là tốt lúc đáp 5 lại là không tốt\\"", "email": "", "phone": "", "agency": "Văn Miếu - Quốc Tử Giám", "position": "", "full_name": "ks2_vmqtg", "department": "Văn Miếu - Quốc Tử Giám", "organization": "Văn Miếu - Quốc Tử Giám"}	f	\N	f	f	2026-07-14 09:04:51.040398+00	464	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	draft
